// 1. 创建背景 Canvas 的函数
function createILoveUSDollarBackground() {
  let canvas = document.getElementById("ILoveUSDollar");
  if (!canvas) {
    canvas = document.createElement("canvas");
    canvas.id = "ILoveUSDollar";
    document.body.prepend(canvas);
  }

  // 合并样式设置
  Object.assign(canvas.style, {
    position: "fixed",
    top: "0",
    left: "0",
    width: "100%",
    height: "100%",
    pointerEvents: "none",
    zIndex: "-1",
    display: "block"
  });

  canvas.width = window.innerWidth;
  canvas.height = window.innerHeight;
}

// 2. 核心动画逻辑函数
// 使用立即执行函数外层包裹变量，防止多次调用导致监听器和动画循环堆叠
const ILoveUSDollar = (function () {
  let timer = null;
  let items = [];
  let mouse = { x: null, y: null };
  const img = new Image();
  img.src = "data:image/jpeg;base64,";
;

  const CONFIG = {
    COUNT: 175, // 适当调低数量以优化大图渲染性能
    WIDTH: 696,
    HEIGHT: 289
  };

  function Item(canvasW, canvasH) {
    this.reset = function (isInit) {
      this.x = Math.random() * canvasW;
      // 初始化时随机分布在全屏，后续重置时从顶部进入
      this.y = isInit ? Math.random() * canvasH : -CONFIG.HEIGHT;
      this.speedY = 0.5 + Math.random() * 1.5;
      this.speedX = (Math.random() - 0.5) * 1;
    };
    this.reset(true);
  }

  // 返回给外部调用的主函数
  return function () {
    if (window.innerWidth < 768) return;

    const canvas = document.getElementById("ILoveUSDollar");
    if (!canvas) return;
    const ctx = canvas.getContext("2d");

    // 清除旧的动画循环，防止多个 requestAnimationFrame 并行导致变快/卡顿
    if (timer) cancelAnimationFrame(timer);

    // 初始化元素
    items = Array.from({ length: CONFIG.COUNT }, () => new Item(canvas.width, canvas.height));

    // 只绑定一次事件监听
    if (!window._USDollarEventsBound) {
      window.addEventListener("mousemove", (e) => {
        mouse.x = e.clientX;
        mouse.y = e.clientY;
      });
      window.addEventListener("mouseleave", () => {
        mouse.x = null;
        mouse.y = null;
      });
      window._USDollarEventsBound = true;
    }

    function loop() {
      // 只有在 Dark 模式下执行逻辑
      if (document.documentElement.getAttribute("data-theme") === "dark") {
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        items.forEach(item => {
          // 鼠标吸附逻辑
          if (mouse.x !== null) {
            const dx = mouse.x - item.x;
            const dy = mouse.y - item.y;
            const dist = Math.sqrt(dx * dx + dy * dy);
            if (dist < 140) {
              item.x += dx * 0.02;
              item.y += dy * 0.02;
            }
          }

          item.y += item.speedY;
          item.x += item.speedX;

          // 循环边界检测
          if (item.y > canvas.height + CONFIG.HEIGHT) {
            item.reset(false);
          }
          if (item.x < -CONFIG.WIDTH) item.x = canvas.width + CONFIG.WIDTH;
          if (item.x > canvas.width + CONFIG.WIDTH) item.x = -CONFIG.WIDTH;

          if (img.complete) {
            ctx.drawImage(img, item.x - CONFIG.WIDTH / 2, item.y - CONFIG.HEIGHT / 2, CONFIG.WIDTH, CONFIG.HEIGHT);
          }
        });
      } else {
        // 非暗色模式清空画布，减少计算
        ctx.clearRect(0, 0, canvas.width, canvas.height);
      }
      timer = requestAnimationFrame(loop);
    }

    loop();
  };
})();

// 3. 显示及触发函数
function ShowILoveUSDollar() {
  const canvas = document.getElementById("ILoveUSDollar");
  if (canvas) {
    canvas.style.display = "block";
    ILoveUSDollar(); // 启动或重新同步动画
  }
}

// ---------------------------------------------------------
// 自动执行与事件挂载
createILoveUSDollarBackground();

document.addEventListener('pjax:end', () => {
  createILoveUSDollarBackground();
  ShowILoveUSDollar();
});

window.addEventListener('resize', () => {
  const canvas = document.getElementById("ILoveUSDollar");
  if (canvas) {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
  }
});

// ---------------------------------------------------------

ILoveUSDollar()